import React, { useCallback, useMemo, useState } from 'react';
import {
  Input,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { CompanyBankAccountDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useServerPagedListLoading,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListMasterLinPageLayout,
  CatalogFormHistorySlot,
  CatalogLegacyCodeSuffix,
  CatalogListHeaderFilters,
  CatalogRowActionMenu,
  type CatalogBatchDeleteMode,
} from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-tai-khoan-ngan-hang';
const CATALOG_KIND = 'company-bank-accounts';

type FormErrors = Partial<Record<'code' | 'name' | 'bankName' | 'glAccountCode', string>>;

const defaultForm = (): Partial<CompanyBankAccountDto> => ({
  isActive: true,
  glAccountCode: '11212',
  displayOrder: 0,
  accountNumber: '',
  bankName: '',
  branchName: '',
});

const TaiKhoanNganHangPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<CompanyBankAccountDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CompanyBankAccountDto | null>(null);
  const [form, setForm] = useState<Partial<CompanyBankAccountDto>>(defaultForm());
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const openView = useCallback((row: CompanyBankAccountDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEditImpl = useCallback((row: CompanyBankAccountDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService.getCompanyBankAccounts({ search: search || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              type: 'error',
              message: err instanceof Error ? err.message : 'Không tải được danh mục TK ngân hàng',
            });
          }
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch, beginFetch, endFetch]);

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  const openAdd = () => {
    setEditing(null);
    setForm(defaultForm());
    setErrors({});
    setViewOnlyShared(false);
    markClean();
    setModalOpen(true);
  };

  const closeFormModal = () => setModalOpen(false);

  const validate = (): boolean => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Bắt buộc';
    if (!form.name?.trim()) next.name = 'Bắt buộc';
    if (!form.bankName?.trim()) next.bankName = 'Bắt buộc';
    if (!form.glAccountCode?.trim()) next.glAccountCode = 'Bắt buộc';
    setErrors(next);
    if (Object.keys(next).length > 0) {
      scrollToFirstFieldError(TEST_ID);
      return false;
    }
    return true;
  };

  const handleSave = async () => {
    if (!validate()) return;
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateCompanyBankAccount(editing.id, {
          name: form.name!.trim(),
          accountNumber: form.accountNumber?.trim() ?? '',
          bankName: form.bankName!.trim(),
          branchName: form.branchName?.trim() ?? '',
          departmentCode: form.departmentCode?.trim() || undefined,
          glAccountCode: form.glAccountCode!.trim(),
          paymentChannelCode: form.paymentChannelCode?.trim() || undefined,
          displayOrder: form.displayOrder ?? 0,
          isActive: form.isActive ?? true,
        });
      } else {
        await masterService.createCompanyBankAccount({
          code: form.code!.trim(),
          name: form.name!.trim(),
          accountNumber: form.accountNumber?.trim() ?? '',
          bankName: form.bankName!.trim(),
          branchName: form.branchName?.trim() ?? '',
          departmentCode: form.departmentCode?.trim() || undefined,
          glAccountCode: form.glAccountCode!.trim(),
          paymentChannelCode: form.paymentChannelCode?.trim() || undefined,
          displayOrder: form.displayOrder ?? 0,
          isActive: form.isActive ?? true,
        });
      }
      markClean();
      dispatchAppToast(dispatch, {
        type: 'success',
        message: editing ? 'Cập nhật TK ngân hàng thành công' : 'Tạo TK ngân hàng thành công',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: err instanceof Error ? err.message : 'Lưu thất bại',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateCompanyBankAccount(id, {
          name: row.name,
          accountNumber: row.accountNumber,
          bankName: row.bankName,
          branchName: row.branchName,
          departmentCode: row.departmentCode ?? undefined,
          glAccountCode: row.glAccountCode,
          paymentChannelCode: row.paymentChannelCode ?? undefined,
          displayOrder: row.displayOrder,
          isActive: false,
        });
      }));
      dispatchAppToast(dispatch, { type: 'success', message: `Đã ngưng ${ids.length} TK ngân hàng` });
    } else {
      await Promise.all(ids.map(id => masterService.deleteCompanyBankAccount(id)));
      dispatchAppToast(dispatch, { type: 'success', message: `Đã xóa ${ids.length} TK ngân hàng` });
    }
    refresh();
  };

  const filterBar = (
    <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Mã, STK, ngân hàng, chi nhánh..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </LinListFilterField>
    </CatalogListHeaderFilters>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{ title: 'Danh mục tài khoản ngân hàng', titleIconClass: 'fas fa-university' }}
        listTitle="Danh sách TK ngân hàng"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={filterBar}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy TK ngân hàng phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrap} data-testid={`${TEST_ID}-grid`}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>STK</th>
                  <th>Tên</th>
                  <th>Ngân hàng</th>
                  <th>Chi nhánh NH</th>
                  <th>Chi nhánh nội bộ</th>
                  <th>TK 112</th>
                  <th>Kênh TT</th>
                </tr>
              </thead>
              <tbody>
                {items.map(row => (
                  <tr
                    key={row.id}
                    data-testid={`${TEST_ID}-row-${row.code}`}
                    onClick={() => rowMenu.openEditWithPerm(row)}
                    style={{ cursor: 'pointer' }}
                  >
                    <td>{row.code}</td>
                    <td>{row.accountNumber || '—'}</td>
                    <td>{row.name}</td>
                    <td>{row.bankName}</td>
                    <td>{row.branchName}</td>
                    <td>{row.departmentCode || '—'}</td>
                    <td>{row.glAccountCode}</td>
                    <td>{row.paymentChannelCode || '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem TK ngân hàng' : editing ? 'Sửa TK ngân hàng' : 'Thêm TK ngân hàng'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    setErrors(prev => ({ ...prev, code: undefined }));
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
                <CatalogLegacyCodeSuffix testIdPrefix={TEST_ID} code={editing?.code} legacyCode={editing?.legacyCode} />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên hiển thị *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    setErrors(prev => ({ ...prev, name: undefined }));
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Số tài khoản (STK)</label>
              <Input
                value={form.accountNumber ?? ''}
                disabled={viewOnlyShared}
                onChange={e => { markDirty(); setForm(f => ({ ...f, accountNumber: e.target.value })); }}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Ngân hàng *</label>
              <Input
                value={form.bankName ?? ''}
                disabled={viewOnlyShared}
                error={errors.bankName}
                onChange={e => { markDirty(); setForm(f => ({ ...f, bankName: e.target.value })); }}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Chi nhánh ngân hàng</label>
              <Input
                value={form.branchName ?? ''}
                disabled={viewOnlyShared}
                onChange={e => { markDirty(); setForm(f => ({ ...f, branchName: e.target.value })); }}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Chi nhánh nội bộ</label>
              <Input
                value={form.departmentCode ?? ''}
                disabled={viewOnlyShared}
                placeholder="FM06, PN, …"
                onChange={e => { markDirty(); setForm(f => ({ ...f, departmentCode: e.target.value })); }}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>TK kế toán 112 *</label>
              <Input
                value={form.glAccountCode ?? ''}
                disabled={viewOnlyShared}
                error={errors.glAccountCode}
                onChange={e => { markDirty(); setForm(f => ({ ...f, glAccountCode: e.target.value })); }}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Mã kênh thanh toán (import sao kê)</label>
              <Input
                value={form.paymentChannelCode ?? ''}
                disabled={viewOnlyShared}
                onChange={e => { markDirty(); setForm(f => ({ ...f, paymentChannelCode: e.target.value })); }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={form}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => { markDirty(); setForm(f => ({ ...f, isActive: c })); }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            saveDisabled={viewOnlyShared}
            historySlot={editing ? (
              <CatalogFormHistorySlot
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                editing={{ id: editing.id, code: editing.code }}
              />
            ) : undefined}
          />
        </div>
      </Modal>
    </>
  );
};

export default TaiKhoanNganHangPage;
